import { describe, expect, it } from "vitest";
import { rangeLabel } from "../src/summary.js";
import { paginate } from "../src/paginate.js";

describe("rangeLabel", () => {
  it("labels a middle page", () => {
    expect(rangeLabel(2, 10, 35)).toBe("showing 11-20 of 35");
  });
});

describe("paginate", () => {
  const all = Array.from({ length: 23 }, (_, i) => i + 1);

  it("returns a full page of `size` rows", () => {
    const { items, total } = paginate(all, 1, 10);
    expect(items).toHaveLength(10);
    expect(items[0]).toBe(1);
    expect(items[9]).toBe(10);
    expect(total).toBe(23);
  });

  it("row count matches the range label", () => {
    const { items } = paginate(all, 1, 10);
    expect(rangeLabel(1, 10, 23)).toBe("showing 1-10 of 23");
    expect(items).toHaveLength(10);
  });

  it("returns the short final page", () => {
    const { items } = paginate(all, 3, 10);
    expect(items).toEqual([21, 22, 23]);
  });
});

